})() }}

={{ (() => {
  const d = $json;
  const children = [];
  children.push({object:'block',type:'heading_2',heading_2:{rich_text:[{type:'text',text:{content:'📊 국가별 현황'}}]}});
  d.summaries.filter(s=>!s.error).forEach(s => {
    children.push({object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content: s.name+' — AS '+s.apple+' (배너 '+s.appleBanners+') / GP '+s.google+' (배너 '+s.googleBanners+') / NX: AS '+s.nxApple+' GP '+s.nxGoogle}}]}});
  });
  children.push({object:'block',type:'heading_2',heading_2:{rich_text:[{type:'text',text:{content:'🎯 NEXON 피쳐드 ('+d.nexonCount+'개)'}}]}});
  if (d.nexonList.length) {
    d.nexonList.forEach(n => {
      const st = n.stores.map(s=>s==='apple'?'🍎AS':'🟢GP').join(' ');
      const fl = n.countries.map(c=>({KR:'🇰🇷',TW:'🇹🇼',JP:'🇯🇵',US:'🇺🇸',TH:'🇹🇭'}[c]||c)).join(' ');
      const tags = [];
      if(n.banner) tags.push('🔥배너');
      if(n.bothStores) tags.push('⚡양쪽');
      children.push({object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content: n.name+' — '+st+' | '+fl+' | #'+n.rank+' '+(tags.join(' '))}}]}});
    });
  } else {
    children.push({object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content:'피쳐드 없음'}}]}});
  }
  children.push({object:'block',type:'heading_2',heading_2:{rich_text:[{type:'text',text:{content:'📈 장르 Top 5'}}]}});
  d.topGenres.forEach(g => {
    children.push({object:'block',type:'paragraph',paragraph:{rich_text:[{type:'text',text:{content: g.genre+': '+g.count+'개'}}]}});
  });
  children.push({object:'block',type:'divider',divider:{}});
  children.push({object:'block',type:'bookmark',bookmark:{url:'https://store-featured-dash.netlify.app'}});
  return JSON.stringify({
    parent:{page_id:'여기에_REPORT_PAGE_ID_입력'},
    properties:{title:[{text:{content:'📈 피쳐드 리포트 '+d.date}}]},
    icon:{emoji:'📈'},
    children
  });
})() }}

